tasks.command:
python3 -c "
import os
base = os.path.join(os.getcwd(), 'src', 'middleware', 'aws')
print('Writing to', base)

ops = '/// AWS AppConfig Data operations
///
/// API Reference: https://docs.aws.amazon.com/appconfig/2019-10-09/APIReference/API_Operations_AWS_AppConfig_Data.html
use crate::{KeyValue, StringValue};

use super::*;

/// Builder for AppConfig Data-specific OpenTelemetry spans.
///
/// This enum serves as a namespace for AppConfig Data operation span builders.
/// Each operation provides a specific method to create properly configured
/// spans with AppConfig Data-specific attributes.
pub enum AppConfigDataSpanBuilder {}

impl AwsSpanBuilder<'_> {
    /// Creates an AppConfig Data operation span builder.
    ///
    /// This method creates a span builder configured for AppConfig Data
    /// operations with the application identifier as the primary resource identifier.
    ///
    /// # Arguments
    ///
    /// * \x60method\x60 - The AppConfig Data operation method name
    /// * \x60application_id\x60 - Optional application identifier for the operation
    pub fn appconfigdata(
        method: impl Into<StringValue>,
        application_id: Option<impl Into<StringValue>>,
    ) -> Self {
        let mut attributes = Vec::new();
        if let Some(id) = application_id {
            attributes.push(KeyValue::new(
                "aws.appconfigdata.application_id",
                id.into(),
            ));
        }
        Self::client("AppConfigData", method, attributes)
    }
}

macro_rules! appconfigdata_global_operation {
    ($op: ident) => {
        impl AppConfigDataSpanBuilder {
            #[doc = concat!("Creates a span builder for the AppConfig Data ", stringify!($op), " operation.")]
            #[inline]
            pub fn $op<'a>() -> AwsSpanBuilder<'a> {
                AwsSpanBuilder::appconfigdata(stringify_camel!($op), None::<StringValue>)
            }
        }
    };
}

macro_rules! appconfigdata_application_operation {
    ($op: ident) => {
        impl AppConfigDataSpanBuilder {
            #[doc = concat!("Creates a span builder for the AppConfig Data ", stringify!($op), " operation.")]
            ///
            /// # Arguments
            ///
            /// * \x60application_id\x60 - The application identifier
            pub fn $op<'a>(
                application_id: impl Into<StringValue>,
            ) -> AwsSpanBuilder<'a> {
                AwsSpanBuilder::appconfigdata(stringify_camel!($op), Some(application_id))
            }
        }
    };
}

// Session operations
appconfigdata_application_operation!(start_configuration_session);

// Configuration retrieval operations
appconfigdata_global_operation!(get_latest_configuration);
'

with open(os.path.join(base, 'operations', 'appconfigdata.rs'), 'w') as f:
    f.write(ops)
print('ops written')

fb = '/// AWS AppConfig Data fluent builder instrumentation implementations
use super::{utils::*, *};

// Session operations
impl<'a> AwsBuilderInstrument<'a> for StartConfigurationSessionFluentBuilder {
    fn build_aws_span(&self) -> AwsSpanBuilder<'a> {
        let application_id = self
            .get_application_identifier()
            .clone()
            .unwrap_or_default();
        let attributes = attributes![
            self.get_environment_identifier()
                .as_attribute("aws.appconfigdata.environment_id"),
            self.get_configuration_profile_identifier()
                .as_attribute("aws.appconfigdata.configuration_profile_id"),
            self.get_required_minimum_poll_interval_in_seconds()
                .map(|v| KeyValue::new(
                    "aws.appconfigdata.required_minimum_poll_interval_in_seconds",
                    v as i64,
                )),
        ];
        AppConfigDataSpanBuilder::start_configuration_session(application_id).attributes(attributes)
    }
}
impl InstrumentedFluentBuilderOutput for StartConfigurationSessionOutput {}
instrument_aws_operation!(aws_sdk_appconfigdata::operation::start_configuration_session);

// Configuration retrieval operations
impl<'a> AwsBuilderInstrument<'a> for GetLatestConfigurationFluentBuilder {
    fn build_aws_span(&self) -> AwsSpanBuilder<'a> {
        AppConfigDataSpanBuilder::get_latest_configuration()
    }
}
impl InstrumentedFluentBuilderOutput for GetLatestConfigurationOutput {
    fn extract_attributes(&self) -> impl IntoIterator<Item = KeyValue> {
        attributes![
            self.content_type()
                .as_attribute("aws.appconfigdata.content_type"),
            self.version_label()
                .as_attribute("aws.appconfigdata.version_label"),
            Some(KeyValue::new(
                "aws.appconfigdata.next_poll_interval_in_seconds",
                self.next_poll_interval_in_seconds() as i64,
            )),
        ]
    }
}
instrument_aws_operation!(aws_sdk_appconfigdata::operation::get_latest_configuration);
'

with open(os.path.join(base, 'instrumentation', 'fluent_builder', 'appconfigdata.rs'), 'w') as f:
    f.write(fb)
print('fb written')
"
